SELECT indicator_id
FROM indicator_sectors
WHERE sector_id = 1;

SELECT indicator_description, cumulative
FROM economic_indicators
WHERE cumulative = (SELECT MAX(cumulative) FROM economic_indicators);

SELECT AVG(report_count) AS average_reports_created
FROM (
    SELECT user_id, COUNT(report_id) AS report_count
    FROM reports
    GROUP BY user_id
);
